380: double G1CollectionSet::select_candidates_from_marking(double time_remaining_ms) {
381:   uint num_expensive_regions = 0;
382:   uint num_inital_regions = 0;
383:   uint num_initial_groups = 0;
384:   uint num_optional_regions = 0;
385: 
386:   double predicted_initial_time_ms = 0.0;
387:   double predicted_optional_time_ms = 0.0;
