389:   double optional_threshold_ms = time_remaining_ms * _policy->optional_prediction_fraction();
390: 
391:   uint min_old_cset_length = _policy->calc_min_old_cset_length(candidates()->last_marking_candidates_length());
392:   uint max_old_cset_length = MAX2(min_old_cset_length, _policy->calc_max_old_cset_length());
393:   bool check_time_remaining = _policy->use_adaptive_young_list_length();
394: 
395:   G1CSetCandidateGroupList* from_marking_groups = &candidates()->from_marking_groups();
396: 
397:   log_debug(gc, ergo, cset)("Start adding marking candidates to collection set. "
398:                             "Min %u regions, max %u regions, available %u regions (%u groups), "
399:                             "time remaining %1.2fms, optional threshold %1.2fms",
400:                             min_old_cset_length, max_old_cset_length, from_marking_groups->num_regions(), from_marking_groups->length(),
401:                             time_remaining_ms, optional_threshold_ms);
402: 
403:   G1CSetCandidateGroupList selected_groups;
404: 
405:   for (G1CSetCandidateGroup* group : *from_marking_groups) {
406:     if (num_inital_regions + num_optional_regions >= max_old_cset_length) {
407:       // Added maximum number of old regions to the CSet.
408:       print_finish_message("Maximum number of regions reached", true);
409:       break;
410:     }
411: 
412:     double predicted_time_ms = group->predict_group_total_time_ms();
413: 
414:     time_remaining_ms = MAX2(time_remaining_ms - predicted_time_ms, 0.0);
415:     // Add regions to old set until we reach the minimum amount
416:     if (num_inital_regions < min_old_cset_length) {
417: 
418:       num_initial_groups++;
419: 
420:       add_group_to_collection_set(group);
421:       selected_groups.append(group);
422: 
423:       num_inital_regions += group->length();
424: 
425:       predicted_initial_time_ms += predicted_time_ms;
426:       // Record the number of regions added with no time remaining
427:       if (time_remaining_ms == 0.0) {
428:         num_expensive_regions += group->length();
429:       }
430:     } else if (!check_time_remaining) {
