432:       // to the CSet if we reach the minimum.
433:       print_finish_message("Region amount reached min", true);
434:       break;
435:     } else {
436:       // Keep adding regions to old set until we reach the optional threshold
437:       if (time_remaining_ms > optional_threshold_ms) {
438:         num_initial_groups++;
439: 
440:         add_group_to_collection_set(group);
