331: void G1ConcurrentMarkThread::concurrent_cycle_end(bool mark_cycle_completed) {
332:   ConcurrentGCBreakpoints::at("BEFORE CLEANUP COMPLETED");
333:   // Update the number of full collections that have been
334:   // completed. This will also notify the G1OldGCCount_lock in case a
335:   // Java thread is waiting for a full GC to happen (e.g., it
336:   // called System.gc() with +ExplicitGCInvokesConcurrent).
337:   SuspendibleThreadSetJoiner sts_join;
338:   G1CollectedHeap::heap()->increment_old_marking_cycles_completed(true /* concurrent */,
339:                                                                   mark_cycle_completed /* heap_examined */);
340: 
341:   _cm->concurrent_cycle_end(mark_cycle_completed);
342:   ConcurrentGCBreakpoints::notify_active_to_idle();
343: }
