{"content":"1074: void G1ConcurrentMark::scan_root_regions() {
1075:   // scan_in_progress() will have been set to true only if there was
1076:   // at least one root region to scan. So, if it's false, we
1077:   // should not attempt to do any further work.
1078:   if (root_regions()->scan_in_progress()) {
1079:     assert(!has_aborted(), "Aborting before root region scanning is finished not supported.");
1080: 
1081:     // Assign one worker to each root-region but subject to the max constraint.
1082:     const uint num_workers = MIN2(root_regions()->num_root_regions(),
1083:                                   _max_concurrent_workers);
1084: 
1085:     G1CMRootRegionScanTask task(this);
1086:     log_debug(gc, ergo)("Running %s using %u workers for %u work units.",
1087:                         task.name(), num_workers, root_regions()->num_root_regions());
1088:     _concurrent_workers->run_task(&task, num_workers);
1089: 
1090:     // It's possible that has_aborted() is true here without actually
1091:     // aborting the survivor scan earlier. This is OK as it's
1092:     // mainly used for sanity checking.
1093:     root_regions()->scan_finished();
1094:   }
1095: }
